const fs = require('fs');
const path = '/opt/notifier/config/bot-config.json';
let config = {};
try {
  config = JSON.parse(fs.readFileSync(path, 'utf8'));
} catch (e) {
  config = {
    enabled: false,
    business_hours_start: "09:00",
    business_hours_end: "18:00",
    business_hours_timezone: "Europe/Madrid",
    out_of_hours_message: "Gracias por su mensaje. Horario: 09:00 a 18:00."
  };
}
return [{ json: { config, ...$input.all()[0].json } }];

const item = $input.all()[0].json;
const config = item.config;
if (!config.enabled) {
  return [{ json: { passes: false, reason: "bot_disabled" } }];
}

// Business hours check
const tz = config.business_hours_timezone || 'Europe/Madrid';
const now = new Date();
const localTimeStr = now.toLocaleTimeString('en-US', { timeZone: tz, hour12: false });
const [hour, min] = localTimeStr.split(':').map(Number);

const [startHour, startMin] = config.business_hours_start.split(':').map(Number);
const [endHour, endMin] = config.business_hours_end.split(':').map(Number);

const nowMinutes = hour * 60 + min;
const startMinutes = startHour * 60 + startMin;
const endMinutes = endHour * 60 + endMin;

const inHours = nowMinutes >= startMinutes && nowMinutes <= endMinutes;

return [{
  json: {
    ...item,
    passes: inHours,
    reason: inHours ? "" : "out_of_hours"
  }
}];

const webhookData = $node["Evolution Webhook"].json;
const appItem = $node["Fetch Last Appointment"].json;
const phone = '+' + webhookData.data.key.remoteJid.split('@')[0];
const patientName = appItem.patient_name || webhookData.pushName || 'Paciente';

// We need to retrieve or create the PatientProfile and ConversationSession via PostgreSQL in the next steps.
return [{
  json: {
    phone,
    patientName,
    appointmentId: appItem.id || null,
    messageContent: webhookData.data.message.conversation || '',
    appointmentDate: appItem.appointment_date || null,
    appointmentTime: appItem.appointment_time || null,
    appointmentType: appItem.appointment_type || null
  }
}];

const classifierResult = $node["Layer 1 Topic Classifier"].json;
const allowedTopics = ["appointment_time", "appointment_date", "appointment_type", "clinic_location", "appointment_confirmation"];
let parsedResult = {};
try {
  parsedResult = JSON.parse(classifierResult.text || classifierResult.message.content);
} catch (e) {
  parsedResult = { topic: "other", confidence: 0.5 };
}

const isAllowed = allowedTopics.includes(parsedResult.topic) && parsedResult.confidence >= 0.7;
return [{
  json: {
    topic: parsedResult.topic,
    confidence: parsedResult.confidence,
    allowed: isAllowed,
    reason: isAllowed ? "" : `blocked_or_low_confidence:${parsedResult.topic}`
  }
}];

