=Eres un bot de gestión de citas médicas de la clínica. Sigue estrictamente estas reglas:
1. Solo responde al tema: {{$node["Parse Classification"].json.topic}}.
2. Con respecto a la cita de {{$node["Prepare Profile Query Info"].json.patientName}}:
   - Fecha: {{$node["Prepare Profile Query Info"].json.appointmentDate}}
   - Hora: {{$node["Prepare Profile Query Info"].json.appointmentTime}}
   - Especialidad: {{$node["Prepare Profile Query Info"].json.appointmentType}}
3. No proporciones diagnósticos, medicamentos ni consejos sobre salud o tratamientos.
4. No reveles ningún dato ajeno.
5. El historial de conversación actual es:
   {{JSON.stringify($node["Upsert Session Info"].json.context_window)}}
6. El resumen del perfil del paciente es:
   {{JSON.stringify($node["Upsert Patient Profile"].json.cross_appointment_summary)}}
7. Responde de forma muy profesional y breve (menos de 200 caracteres).

Mensaje actual del paciente: "{{$node["Prepare Profile Query Info"].json.messageContent}}"

Escribe tu respuesta corta en español:

parameters.jsCode:
const generatedText = $node["Layer 2 Prompt Agent"].json.text || $node["Layer 2 Prompt Agent"].json.message.content || '';
const medicalBlocklist = [
  "antibiótico", "anestesia", "caries", "conducto", "empaste",
  "endodoncia", "extracción", "gingivitis", "implante", "inflamación",
  "infección", "ortodoncia", "periodontitis", "prótesis", "pulir",
  "rayos x", "radiografía", "sangrado", "tumor", "úlcera"
];

const lowerText = generatedText.toLowerCase();
let hasMedicalViolations = false;
for (const term of medicalBlocklist) {
  if (lowerText.includes(term)) {
    hasMedicalViolations = true;
    break;
  }
}

const tooLong = generatedText.length > 200;
const isApproved = !hasMedicalViolations && !tooLong && generatedText.trim().length > 0;

return [{
  json: {
    replyText: generatedText,
    approved: isApproved,
    reason: isApproved ? "" : (hasMedicalViolations ? "medical_term_detected" : "too_long")
  }
}];

const session = $node["Upsert Session Info"].json;
const newMsgPatient = { role: "patient", content: $node["Prepare Profile Query Info"].json.messageContent, timestamp: new Date().toISOString() };
const newMsgBot = { role: "bot", content: $node["Layer 3 Post-Validation"].json.replyText, timestamp: new Date().toISOString() };

const window = Array.isArray(session.context_window) ? session.context_window : [];
window.push(newMsgPatient);
window.push(newMsgBot);

// Keep last 10 messages
if (window.length > 10) {
  window.splice(0, window.length - 10);
}

return [{ json: { context_window: window, sessionId: session.id } }];
